    resetGame();
    // 通知Phaser场景启动
    EventBus.emit('scene-changed', { key: 'MainGame' });
    // TODO: 目前不能直接调用 scene.start，因为React没有scene实例，我们使用EventBus，或者在Boot中延迟启动
    // 在这里我们采取简单做法，由于Boot已经加载完，我们可以让MainGame通过 EventBus 监听
  };

  const handleRestart = () => {
    resetGame();
    EventBus.emit('restart-game');
